// src/components/DashboardAluno.jsx
import React, { useEffect, useState } from "react";
import axios from "axios";
import { useAuth } from "./context/AuthContext";

export default function DashboardAluno() {
  const { user } = useAuth();
  const [agendamentos, setAgendamentos] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedCard, setSelectedCard] = useState(null); // 'solicitacoes' | 'proximos' | 'atendidos'

  useEffect(() => {
    axios
      .get("/api/agendamentos/meus")
      .then((res) => setAgendamentos(res.data))
      .catch((err) => console.error("Erro ao carregar agendamentos:", err))
      .finally(() => setLoading(false));
  }, []);

  // Categorias
  const solicitacoes = agendamentos.filter(a => a.status === "Solicitado");
  const proximos = agendamentos.filter(a => a.status !== "Solicitado" && a.status !== "Atendido");
  const atendidos = agendamentos.filter(a => a.status === "Atendido");

  const firstName = (user.usuario || "").split(" ")[0];

  const toggleCard = (key) => {
    setSelectedCard(prev => prev === key ? null : key);
  };

  if (loading) {
    return <p className="text-center py-8">Carregando seu dashboard...</p>;
  }

  return (
    <div className="max-w-3xl mx-auto py-10 px-4">
      <h1 className="text-3xl font-bold mb-8">Olá, {firstName}!</h1>

      <div className="bg-blue-100 rounded-2xl shadow p-8 mb-4">
        <div className="text-lg font-semibold mb-4">Resumo rápido</div>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div
            onClick={() => toggleCard("solicitacoes")}
            className={`cursor-pointer bg-white rounded-xl p-6 shadow text-center transition ${
              selectedCard === "solicitacoes" ? "ring-4 ring-blue-200" : ""
            }`}
          >
            <div className="font-bold text-3xl text-[#3172C0]">{solicitacoes.length}</div>
            <div className="text-gray-600 mt-2">Minhas Solicitações</div>
          </div>

          <div
            onClick={() => toggleCard("proximos")}
            className={`cursor-pointer bg-white rounded-xl p-6 shadow text-center transition ${
              selectedCard === "proximos" ? "ring-4 ring-blue-200" : ""
            }`}
          >
            <div className="font-bold text-3xl text-[#3172C0]">{proximos.length}</div>
            <div className="text-gray-600 mt-2">Agendamentos Próximos</div>
          </div>

          <div
            onClick={() => toggleCard("atendidos")}
            className={`cursor-pointer bg-white rounded-xl p-6 shadow text-center transition ${
              selectedCard === "atendidos" ? "ring-4 ring-blue-200" : ""
            }`}
          >
            <div className="font-bold text-3xl text-[#3172C0]">{atendidos.length}</div>
            <div className="text-gray-600 mt-2">Agendamentos Atendidos</div>
          </div>
        </div>
      </div>

      {/* Lista que expande ao clicar no card */}
      {selectedCard === "solicitacoes" && (
        <div className="bg-white rounded-2xl shadow p-6 mb-4">
          <h2 className="text-lg font-bold mb-4">Últimas Solicitações</h2>
          <ul className="space-y-3">
            {solicitacoes.slice(0, 5).map(a => (
              <li
                key={a.id}
                className="flex justify-between items-center bg-gray-50 rounded-xl px-5 py-3 shadow-sm"
              >
                <span className="text-gray-800 font-medium">
                  {a.data.slice(0,10).split('-').reverse().join('/')}
                </span>
                <span className="px-4 py-1 rounded-full bg-yellow-100 text-yellow-800 font-semibold">
                  Pendente
                </span>
              </li>
            ))}
            {solicitacoes.length === 0 && (
              <li className="text-gray-500">Nenhuma solicitação pendente.</li>
            )}
          </ul>
        </div>
      )}

      {selectedCard === "proximos" && (
        <div className="bg-white rounded-2xl shadow p-6 mb-4">
          <h2 className="text-lg font-bold mb-4">Próximos Agendamentos</h2>
          <ul className="space-y-3">
            {proximos.slice(0, 5).map(a => (
              <li
                key={a.id}
                className="bg-gray-50 rounded-xl px-5 py-3 shadow-sm"
              >
                <div className="font-medium">{a.disciplinaNome || a.disciplina_id}</div>
                <div className="text-gray-600">
                  {a.data.slice(0,10).split('-').reverse().join('/')} — {a.hora}
                </div>
              </li>
            ))}
            {proximos.length === 0 && (
              <li className="text-gray-500">Nenhum agendamento próximo.</li>
            )}
          </ul>
        </div>
      )}

      {selectedCard === "atendidos" && (
        <div className="bg-white rounded-2xl shadow p-6 mb-4">
          <h2 className="text-lg font-bold mb-4">Agendamentos Atendidos</h2>
          <ul className="space-y-3">
            {atendidos.slice(0, 5).map(a => (
              <li
                key={a.id}
                className="bg-gray-50 rounded-xl px-5 py-3 shadow-sm"
              >
                <div className="font-medium">{a.disciplinaNome || a.disciplina_id}</div>
                <div className="text-gray-600">
                  {a.data.slice(0,10).split('-').reverse().join('/')} — {a.hora}
                </div>
              </li>
            ))}
            {atendidos.length === 0 && (
              <li className="text-gray-500">Nenhum agendamento atendido.</li>
            )}
          </ul>
        </div>
      )}
    </div>
  );
}
